 1→import React, {useEffect} from 'react';
 2→import {StyleSheet, View, type ViewStyle} from 'react-native';
 3→import Animated, {
 4→  useSharedValue,
 5→  useAnimatedStyle,
 6→  withRepeat,
 7→  withTiming,
 8→  interpolate,
 9→} from 'react-native-reanimated';
10→import {useTheme} from '../theme/ThemeProvider';
11→import {radii} from '../theme/spacing';
12→
13→interface SkeletonLoaderProps {
14→  width?: number | string;
15→  height?: number;
16→  borderRadius?: number;
17→  style?: ViewStyle;
18→}
19→
20→export function SkeletonLoader({
21→  width = '100%',
22→  height = 16,
23→  borderRadius = radii.sm,
24→  style,
25→}: SkeletonLoaderProps) {
26→  const {colors} = useTheme();
27→  const shimmer = useSharedValue(0);
28→
29→  useEffect(() => {
30→    shimmer.value = withRepeat(withTiming(1, {duration: 1200}), -1, true);
31→  }, [shimmer]);
32→
33→  const animatedStyle = useAnimatedStyle(() => ({
34→    opacity: interpolate(shimmer.value, [0, 1], [0.3, 0.7]),
35→  }));
36→
37→  return (
38→    <Animated.View
39→      style={[
40→        {
41→          width: width as any,
42→          height,
43→          borderRadius,
44→          backgroundColor: colors.bgSecondary,
45→        },
46→        animatedStyle,
47→        style,
48→      ]}
49→    />
50→  );
51→}
52→
53→export function PostCardSkeleton() {
54→  const {colors} = useTheme();
55→  return (
56→    <View
57→      style={[
58→        skeletonStyles.card,
59→        {backgroundColor: colors.bgCard, borderColor: colors.borderCard},
60→      ]}>
61→      <SkeletonLoader height={160} borderRadius={0} />
62→      <View style={skeletonStyles.content}>
63→        <View style={skeletonStyles.authorRow}>
64→          <SkeletonLoader width={22} height={22} borderRadius={11} />
65→          <SkeletonLoader width={100} height={14} />
66→        </View>
67→        <SkeletonLoader width="80%" height={18} />
68→        <SkeletonLoader width="100%" height={14} />
69→        <SkeletonLoader width="60%" height={14} />
70→      </View>
71→    </View>
72→  );
73→}
74→
75→const skeletonStyles = StyleSheet.create({
76→  card: {
77→    borderRadius: radii.xl,
78→    borderWidth: 1,
79→    overflow: 'hidden',
80→  },
81→  content: {
82→    padding: 16,
83→    gap: 10,
84→  },
85→  authorRow: {
86→    flexDirection: 'row',
87→    alignItems: 'center',
88→    gap: 8,
89→  },
90→});
