  1→import React from 'react';
  2→import {
  3→  FlatList,
  4→  Image,
  5→  Pressable,
  6→  StyleSheet,
  7→  Text,
  8→  View,
  9→} from 'react-native';
 10→import {useQuery} from '@tanstack/react-query';
 11→import {useNavigation} from '@react-navigation/native';
 12→import {NativeStackNavigationProp} from '@react-navigation/native-stack';
 13→import {useTheme} from '../../theme/ThemeProvider';
 14→import {fonts, typeScale} from '../../theme/typography';
 15→import {spacing, radii, shadows} from '../../theme/spacing';
 16→import {mobileApi, type JournalItem} from '../../lib/api/mobileApi';
 17→import type {RootStackParamList} from '../../navigation/types';
 18→
 19→interface RelatedPostsProps {
 20→  journalId: string;
 21→}
 22→
 23→const extractImage = (content: string | null | undefined): string | null => {
 24→  if (!content) return null;
 25→  try {
 26→    const parsed = JSON.parse(content);
 27→    const find = (node: any): string | null => {
 28→      if (node.type === 'image' && node.src) return node.src;
 29→      if (node.children) {
 30→        for (const child of node.children) {
 31→          const found = find(child);
 32→          if (found) return found;
 33→        }
 34→      }
 35→      return null;
 36→    };
 37→    return find(parsed.root ?? parsed);
 38→  } catch {
 39→    return null;
 40→  }
 41→};
 42→
 43→export function RelatedPosts({journalId}: RelatedPostsProps) {
 44→  const {colors} = useTheme();
 45→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 46→
 47→  const {data, isLoading} = useQuery({
 48→    queryKey: ['related-posts', journalId],
 49→    queryFn: () => mobileApi.getRelatedPosts(journalId),
 50→    enabled: Boolean(journalId),
 51→  });
 52→
 53→  const posts = data?.data ?? [];
 54→
 55→  if (isLoading || posts.length < 2) return null;
 56→
 57→  return (
 58→    <View style={styles.container}>
 59→      <Text style={[styles.title, {color: colors.textHeading}]}>
 60→        Related Posts
 61→      </Text>
 62→      <FlatList
 63→        horizontal
 64→        data={posts}
 65→        keyExtractor={item => item.id}
 66→        showsHorizontalScrollIndicator={false}
 67→        contentContainerStyle={styles.scrollContent}
 68→        renderItem={({item}) => {
 69→          const image = extractImage(item.content);
 70→          return (
 71→            <Pressable
 72→              onPress={() =>
 73→                navigation.push('PostDetail', {journalId: item.id})
 74→              }
 75→              style={[
 76→                styles.card,
 77→                {
 78→                  backgroundColor: colors.bgCard,
 79→                  borderColor: colors.borderCard,
 80→                },
 81→                shadows(colors).cardSm,
 82→              ]}>
 83→              {image && (
 84→                <Image
 85→                  source={{uri: image}}
 86→                  style={styles.cardImage}
 87→                  resizeMode="cover"
 88→                />
 89→              )}
 90→              <View style={styles.cardContent}>
 91→                <Text
 92→                  style={[styles.cardTitle, {color: colors.textHeading}]}
 93→                  numberOfLines={2}>
 94→                  {item.title || 'Untitled'}
 95→                </Text>
 96→                <Text
 97→                  style={[styles.cardAuthor, {color: colors.textMuted}]}
 98→                  numberOfLines={1}>
 99→                  {item.users?.name || 'Unknown'}
100→                </Text>
101→              </View>
102→            </Pressable>
103→          );
104→        }}
105→      />
106→    </View>
107→  );
108→}
109→
110→const styles = StyleSheet.create({
111→  container: {
112→    marginTop: spacing.xl,
113→  },
114→  title: {
115→    ...typeScale.h3,
116→    marginBottom: spacing.md,
117→  },
118→  scrollContent: {
119→    gap: spacing.md,
120→  },
121→  card: {
122→    width: 180,
123→    borderRadius: radii.xl,
124→    borderWidth: 1,
125→    overflow: 'hidden',
126→  },
127→  cardImage: {
128→    width: '100%',
129→    height: 100,
130→  },
131→  cardContent: {
132→    padding: spacing.md,
133→    gap: 4,
134→  },
135→  cardTitle: {
136→    fontFamily: fonts.heading.semiBold,
137→    fontSize: 13,
