203→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
204→    const formData = new FormData();
205→
206→    const lexicalPayload = {
207→      root: {
208→        children: [
209→          {
210→            type: 'paragraph',
211→            children: [
212→              {
213→                type: 'text',
214→                text: payload.plainText,
215→                detail: 0,
216→                format: 0,
217→                mode: 'normal',
218→                style: '',
219→                version: 1,
220→              },
221→            ],
222→            direction: null,
223→            format: '',
224→            indent: 0,
225→            version: 1,
226→          },
227→        ],
228→        direction: null,
229→        format: '',
230→        indent: 0,
231→        type: 'root',
232→        version: 1,
233→      },
234→    };
235→
236→    formData.append('title', payload.title);
237→    formData.append('content', JSON.stringify(lexicalPayload));
238→    formData.append('post_type', 'text');
239→
240→    return apiRequest<{ message?: string }>('/save-journal', {
241→      method: 'POST',
242→      headers: {
243→        ...authHeaders(token),
244→      },
245→      body: formData,
246→      timeoutMs: 30000,
247→      retries: 0,
248→    });
249→  },
250→};
